import { CSSProperties } from 'react';
import { ClassValue } from 'clsx';

/** CSS custom properties merged with standard React style properties. */
type CSSWithVars = CSSProperties & Record<`--${string}`, string | number | undefined>;
/**
 * Type-safe inline styles containing CSS custom properties (`--*`).
 * Accepts standard CSS properties and any `--`-prefixed custom property.
 */
declare function cssVars(vars: CSSWithVars): CSSProperties;
/**
 * Merges class names using clsx and tailwind-merge, resolving Tailwind CSS conflicts.
 *
 * @param inputs - Class values to merge (strings, arrays, objects, etc.)
 * @returns A single merged class string with Tailwind conflicts resolved
 */
declare function cn(...inputs: ClassValue[]): string;

export { type CSSWithVars, cn, cssVars };
